// HasLines applies the HasEdge predicate on the "lines" edge.
func HasLines() predicate.POSReturn {
	return predicate.POSReturn(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, LinesTable, LinesColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasLinesWith applies the HasEdge predicate on the "lines" edge with a given conditions (other predicates).
func HasLinesWith(preds ...predicate.POSReturnLine) predicate.POSReturn {
	return predicate.POSReturn(func(s *sql.Selector) {
		step := newLinesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.POSReturn) predicate.POSReturn {
	return predicate.POSReturn(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.POSReturn) predicate.POSReturn {
	return predicate.POSReturn(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.POSReturn) predicate.POSReturn {
	return predicate.POSReturn(sql.NotPredicates(p))
}
